import{_ as p,C as n,o as s,c as h,j as a,a as i,E as t,a3 as m}from"./chunks/framework.CVjg771q.js";const P=JSON.parse('{"title":"了凡四训·立命之学","description":"第一篇，云谷禅师授立命之说。","frontmatter":{"title":"了凡四训·立命之学","description":"第一篇，云谷禅师授立命之说。","category":"guide","aliases":["立命之学","了凡四训第一篇"],"source":["《了凡四训》"]},"headers":[],"relativePath":"lizhimingde/liaofan-sixun/chapter-01.md","filePath":"lizhimingde/liaofan-sixun/chapter-01.md","lastUpdated":1781102614000}'),u={name:"lizhimingde/liaofan-sixun/chapter-01.md"};function g(c,e,x,b,f,_){const r=n("DaoReadingPrelude"),o=n("DaoOriginalReading"),d=n("DaoLineGuide"),l=n("DaoKeywordCards");return s(),h("div",null,[e[0]||(e[0]=a("h1",{id:"了凡四训·立命之学",tabindex:"-1"},[i("了凡四训·立命之学 "),a("a",{class:"header-anchor",href:"#了凡四训·立命之学","aria-label":'Permalink to "了凡四训·立命之学"'},"​")],-1)),t(r,{title:"从孔公算定到云谷点破",summary:"立命之学是了凡四训第一篇。袁了凡自述早年被孔先生算定一生，从此澹然无求；后在栖霞山遇云谷禅师，禅师以命由我作，福自己求点破他的宿命论，教他改过迁善、持准提咒、力行功过格。了凡从此改号，不再落凡夫窠臼，最终突破了孔公的预言。",points:[{label:"缘起",text:"孔公算定一生——进退有命，迟速有时。"},{label:"转折",text:"云谷禅师：极善之人，数拘他不定。"},{label:"实践",text:"功过格、准提咒、三千善行——改命不在空谈。"}],hint:"这一篇最适合先顺着了凡的自述走一遍，看他怎样从认命到改命。"}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),t(o,{tone:"ink",density:"comfortable",defaultMode:"regular",modeSwitch:!1,paragraphs:["余童年丧父，老母命弃举业学医，谓可以养生，可以济人，且习一艺以成名，尔父夙心也。后余在慈云寺，遇一老者，修髯伟貌，飘飘若仙，余敬礼之。语余曰：子仕路中人也，明年即进学，何不读书？余告以故，并叩老者姓氏里居。曰：吾姓孔，云南人也。得邵子皇极数正传，数该传汝。余引归，告母。母曰：善待之。试其数，纤悉皆验。余遂启读书之念，谋之表兄沈称，言：郁海谷先生，在沈友夫家开馆，我送汝寄学甚便。余遂礼郁为师。","孔为余起数：县考童生，当十四名；府考七十一名，提学考第九名。明年赴考，三处名数皆合。复为卜终身休咎，言：某年考第几名，某年当补廪，某年当贡，贡后某年，当选四川一大尹，在任三年半，即宜告归。五十三岁八月十四日丑时，当终於正寝，惜无子。余备录而谨记之。自此以后，凡遇考校，其名数先后，皆不出孔公所悬定者。独算余食廪米九十一石五斗当出贡；及食米七十一石，屠宗师即批准补贡，余窃疑之。后果为署印杨公所驳，直至丁卯年，殷秋溟宗师见余场中备卷，叹曰：五策，即五篇奏议也，岂可使博洽淹贯之儒，老於窗下乎！遂依县申文准贡，连前食米计之，实九十一石五斗也。余因此益信进退有命，迟速有时，澹然无求矣。","贡入燕都，留京一年，终日静坐，不阅文字。己巳归，游南雍，未入监，先访云谷会禅师於栖霞山中，对坐一室，凡三昼夜不瞑目。云谷问曰：凡人所以不得作圣者，只为妄念相缠耳。汝坐三日，不见起一妄念，何也？余曰：吾为孔先生算定，荣辱生死，皆有定数，即要妄想，亦无可妄想。云谷笑曰：我待汝是豪杰，原来只是凡夫。问其故？曰：人未能无心，终为阴阳所缚，安得无数？但惟凡人有数；极善之人，数固拘他不定；极恶之人，数亦拘他不定。汝二十年来，被他算定，不曾转动一毫，岂非是凡夫？","余问曰：然则数可逃乎？曰：命由我作，福自己求。诗书所称，的为明训。我教典中说：求富贵得富贵，求男女得男女，求长寿得长寿。夫妄语乃释迦大戒，诸佛菩萨，岂诳语欺人？余进曰：孟子言：求则得之，是求在我者也。道德仁义可以力求；功名富贵，如何求得？云谷曰：孟子之言不错，汝自错解耳。汝不见六祖说：一切福田，不离方寸；从心而觅，感无不通。求在我，不独得道德仁义，亦得功名富贵；内外双得，是求有益於得也。若不反躬内省，而徒向外驰求，则求之有道，而得之有命矣，内外双失，故无益。","因问：孔公算汝终身若何？余以实告。云谷曰：汝自揣应得科第否？应生子否？余追省良久，曰：不应也。科第中人，有福相，余福薄，又不能积功累行，以基厚福；兼不耐烦剧，不能容人；时或以才智盖人，直心直行，轻言妄谈。凡此皆薄福之相也，岂宜科第哉。地之秽者多生物，水之清者常无鱼；余好洁，宜无子者一；和气能育万物，余善怒，宜无子者二；爱为生生之本，忍为不育之根；余矜惜名节，常不能舍己救人，宜无子者三；多言耗气，宜无子者四；喜饮铄精，宜无子者五；好彻夜长坐，而不知葆元毓神，宜无子者六。其馀过恶尚多，不能悉数。","云谷曰：岂惟科第哉。世间享千金之产者，定是千金人物；享百金之产者，定是百金人物；应饿死者，定是饿死人物；天不过因材而笃，几曾加纤毫意思。即如生子，有百世之德者，定有百世子孙保之；有十世之德者，定有十世子孙保之；有三世二世之德者，定有三世二世子孙保之；其斩焉无后者，德至薄也。汝今既知非。将向来不发科第，及不生子之相，尽情改刷；务要积德，务要包荒，务要和爱，务要惜精神。从前种种，譬如昨日死；从后种种，譬如今日生；此义理再生之身。夫血肉之身，尚然有数；义理之身，岂不能格天。太甲曰：天作孽，犹可违；自作孽，不可活。诗云：永言配命，自求多福。孔先生算汝不登科第，不生子者，此天作之孽，犹可得而违；汝今扩充德性，力行善事，多积阴德，此自己所作之福也，安得而不受享乎？","易为君子谋，趋吉避凶；若言天命有常，吉何可趋，凶何可避？开章第一义，便说：积善之家，必有馀庆。汝信得及否？余信其言，拜而受教。因将往日之罪，佛前尽情发露，为疏一通，先求登科；誓行善事三千条，以报天地祖宗之德。云谷出功过格示余，令所行之事，逐日登记；善则记数，恶则退除，且教持准提咒，以期必验。语余曰：符录家有云：不会书符，被鬼神笑。此有秘传，只是不动念也。执笔书符，先把万缘放下，一尘不起。从此念头不动处，下一点，谓之混沌开基。由此而一笔挥成，更无思虑，此符便灵。凡祈天立命，都要从无思无虑处感格。","孟子论立命之学，而曰：夭寿不贰。夫夭寿，至贰者也。当其不动念时，孰为夭，孰为寿？细分之，丰歉不贰，然后可立贫富之命；穷通不贰，然后可立贵贱之命；夭寿不贰，然后可立生死之命。人生世间，惟死生为重，曰夭寿，则一切顺逆皆该之矣。至修身以俟之，乃积德祈天之事。曰修，则身有过恶，皆当治而去之；曰俟，则一毫觊觎，一毫将迎，皆当斩绝之矣。到此地位，直造先天之境，即此便是实学。汝未能无心，但能持准提咒，无记无数，不令间断，持得纯熟，於持中不持，於不持中持。到得念头不动，则灵验矣。","余初号学海，是日改号了凡；盖悟立命之说，而不欲落凡夫窠臼也。从此而后，终日兢兢，便觉与前不同。前日只是悠悠放任，到此自有战兢惕厉景象，在暗室屋漏中，常恐得罪天地鬼神；遇人憎我毁我，自能恬然容受。到明年礼部考科举，孔先生算该第三，忽考第一；其言不验，而秋闱中式矣。然行义未纯，检身多误；或见善而行之不勇，或救人而心常自疑；或身勉为善，而口有过言；或醒时操持，而醉后放逸；以过折功，日常虚度。自己巳岁发愿，直至己卯岁，历十馀年，而三千善行始完。","时方从李渐庵入关，未及回向。庚辰南还。始请性空，慧空诸上人，就东塔禅堂回向。遂起求子愿，亦许行三千善事。辛巳，生男天启。余行一事，随以笔记；汝母不能书，每行一事，辄用鹅毛管，印一朱圈於历日之上。或施食贫人，或放生命，一日有多至十馀者。至癸未八月，三千之数已满。复请性空辈，就家庭回向。九月十三日，复起求中进士愿，许行善事一万条，丙戌登第，授宝坻知县。","余置空格一册，名曰治心篇。晨起坐堂，家人携付门役，置案上，所行善恶，纤悉必记。夜则设桌於庭，效赵阅道焚香告帝。汝母见所行不多，辄颦蹙曰：我前在家，相助为善，故三千之数得完；今许一万，衙中无事可行，何时得圆满乎？夜间偶梦见一神人，余言善事难完之故。神曰：只减粮一节，万行俱完矣。盖宝坻之田，每亩二分三厘七毫。余为区处，减至一分四厘六毫，委有此事，心颇惊疑。适幻余禅师自五台来，余以梦告之，且问此事宜信否？师曰：善心真切，即一行可当万善，况合县减粮，万民受福乎？吾即捐俸银，请其就五台山斋僧一万而回向之。","孔公算予五十三岁有厄，余未尝祈寿，是岁竟无恙，今六十九矣。书曰：天难谌，命靡常。又云：惟命不於常，皆非诳语。吾於是而知，凡称祸福自己求之者，乃圣贤之言。若谓祸福惟天所命，则世俗之论矣。汝之命，未知若何？即命当荣显，常作落寞想；即时当顺利，常作拂逆想；即眼前足食，常作贫窭想；即人相爱敬，常作恐惧想；即家世望重，常作卑下想；即学问颇优，常作浅陋想。远思扬祖宗之德，近思盖父母之愆；上思报国之恩，下思造家之福；外思济人之急，内思闲己之邪。","务要日日知非，日日改过；一日不知非，即一日安於自是；一日无过可改，即一日无步可进；天下聪明俊秀不少，所以德不加修，业不加广者，只为因循二字，耽阁一生。云谷禅师所授立命之说，乃至精至邃，至真至正之理，其熟玩而勉行之，毋自旷也。"]}),t(d,{lines:[{text:"余童年丧父……余遂礼郁为师。",tone:"缘起 · 遇孔公",guide:"先顺读这段自述，看清了凡怎样从弃举业学医被一位孔姓老者一句话掰回读书之路。孔公的皇极数纤悉皆验——这是了凡对命数的第一重确认。"},{text:"孔为余起数……余因此益信进退有命，迟速有时，澹然无求矣。",tone:"确认 · 命数应验",guide:"这一段是全篇最关键的前情。孔公把了凡一生都算完了——包括哪个阶段考第几名、食廪米多少、何时命终、有子无子。而了凡其后二十年的人生，果然皆不出孔公所悬定者。到了这一步，任何人都会信命。"},{text:"贡入燕都……岂非是凡夫？",tone:"转折 · 云谷点破",guide:"栖霞山三昼夜不瞑目——了凡以命已算定为理由的不动念，被云谷一针见血地戳破：极善之人，数固拘他不定；极恶之人，数亦拘他不定。汝二十年来，被他算定，不曾转动一毫，岂非是凡夫？这不是在说他命不好，而是在说：能被算定，说明你从未真正活过。"},{text:"命由我作，福自己求……内外双失，故无益。",tone:"核心 · 立命之根",guide:"云谷给出全篇最核心的命题：命由我作，福自己求。了凡引孟子求则得之来反驳——道德仁义可以自求，功名富贵怎么求？云谷的回应是关键：六祖说一切福田，不离方寸，求不是向外驰求，而是从心而觅。内外双得或双失，全在一个念头转向。"},{text:"汝自揣应得科第否？……不能悉数。",tone:"自省 · 六条过恶",guide:"云谷不让了凡往外看，而是让他自己说：你觉得自己该不该中进士？该不该有儿子？了凡追省良久，说出六条原因——好洁、善怒、矜惜名节、多言耗气、喜饮铄精、彻夜长坐。这不是自我贬低，而是第一次诚实地看清自己的行为模式。"},{text:"从前种种，譬如昨日死……此自己所作之福也。",tone:"立信 · 义理再生",guide:"从前种种譬如昨日死，从后种种譬如今日生——这句是全篇的精神转折点。云谷不叫他去求神拜佛，而是叫他尽情改刷自己的行为。血肉之身固然有数，但义理之身可以格天——这是改命的原理。"},{text:"云谷出功过格示余……到得念头不动，则灵验矣。",tone:"方法 · 功过格与持咒",guide:"改命不是空谈，要落在可追踪的实处。功过格是行为记录——做了善事记一笔，做了恶事扣一笔。准提咒则是心法——持中不持，不持中持，练到念头不动，才算真正入了门。云谷特意讲符录家的秘传，就是想说：真正的力量不在仪式，在于不动念时那一刻的混沌开基。"},{text:"余初号学海，是日改号了凡……而秋闱中式矣。",tone:"实践 · 初效",guide:"改号是形式，但背后是真的转了。了凡开始战兢惕厉，连在暗室中都不敢得罪天地。第二年孔公算他考第三，他考了第一——这是二十年来的第一次不准。改命不是一下子全变，而是从一个不准开始。"},{text:"余置空格一册，名曰治心篇……万民受福乎？",tone:"升华 · 一行当万善",guide:"了凡许了一万善事的愿，但在衙门里没机会做。后来他为宝坻县减粮——只此一件事，幻余禅师告诉他一行可当万善。这里的关键是：善心真不真。如果真把万民放在心上，一条政策就抵一万件小事。善心真切四个字，是这一段的落眼处。"},{text:"务要日日知非，日日改过……毋自旷也。",tone:"收束 · 因循二字",guide:"全篇最后，了凡把一生的心得归到一句话：天下聪明俊秀不少，所以德不加修、业不加广者，只为因循二字，耽阁一生。因循——就是知道自己该改，但总觉得不急。了凡用自己的一生证明：改命不是等来的，是一天一天改出来的。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),t(l,{items:[{term:"皇极数",pinyin:["huáng","jí","shù"],meaning:"即邵雍所传《皇极经世》中的命理推算之术，以人的生辰八字推演一生吉凶祸福。孔公自称得邵子正传。"},{term:"廪米",pinyin:["lǐn","mǐ"],meaning:"明清两代，生员（秀才）由政府供给粮食，称为食廪。食廪米的数量与出贡资格挂钩，是当时科举制度的一部分。"},{term:"出贡",pinyin:["chū","gòng"],meaning:"秀才升为贡生，进入国子监读书，称为出贡。贡生可参加会试或直接授官，是科举的重要台阶。"},{term:"栖霞山",pinyin:["qī","xiá","shān"],meaning:"位于南京东郊，南朝以降即为佛教胜地。云谷禅师所居之处，了凡在此遇师点破命数。"},{term:"功过格",pinyin:["gōng","guò","gé"],meaning:"一种逐日记录善恶行为的簿册。善行记功，恶行记过，以量化方式督促人改过迁善。盛行于明清善书传统中。"},{term:"准提咒",pinyin:["zhǔn","tí","zhòu"],meaning:"佛教准提菩萨的心咒。云谷教了凡持此咒，目的在于持中不持，不持中持——通过反复持诵使心安住，最终达到念头不动的境界。"},{term:"回向",pinyin:["huí","xiàng"],meaning:"佛教术语，将所修功德回转归向于特定目标或众生。了凡每完成三千善行或万善，即请僧人做回向仪式，将功行归于所求。"},{term:"混沌开基",pinyin:["hùn","dùn","kāi","jī"],meaning:"云谷借符录家的术语讲心法：执笔之前先放下万缘，一尘不起；念头不动时落下的那一点，就是重新开始的起点。喻指修行中那个至诚无念的瞬间。"},{term:"夭寿不贰",pinyin:["yāo","shòu","bù","èr"],meaning:"孟子原文。夭为短命，寿为长命——二者在常人眼中是天壤之别。但云谷引此是说要修到不动念时，连生死都不再是分别的对象，才能立生死之命。"},{term:"治心篇",pinyin:["zhì","xīn","piān"],meaning:"了凡任宝坻知县时自制的功过记录册。每天把善恶行为逐条记下，纤悉必记。这是功过格在官吏日常中的具体化应用。"},{term:"因循",pinyin:["yīn","xún"],meaning:"拖延、苟且、得过且过。了凡认为这是毁掉人一生的最大原因——德不加修，业不加广者，只为因循二字，耽阁一生。"}]}),e[3]||(e[3]=m('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一篇在说什么" tabindex="-1">象：这一篇在说什么 <a class="header-anchor" href="#象-这一篇在说什么" aria-label="Permalink to &quot;象：这一篇在说什么&quot;">​</a></h3><p>立命之学是了凡四训的第一篇，也是全书的基石。它以了凡自述为主线，讲了三个层层递进的故事：第一，孔公以皇极数把他一生算尽，此后二十年一一应验——他因此澹然无求，认了命；第二，在栖霞山遇云谷禅师——禅师一针见血地指出能被算定，说明你从未真正活过；第三，他从功过格和持咒入手，用三千善行把孔公的预言一条条打破了。</p><p>全篇的核心转折不在玄理，而在云谷那一句：从前种种，譬如昨日死；从后种种，譬如今日生。真正要改的，不是外在那条命，而是人对自己行为模式的诚实面对。</p><h3 id="理-为什么这一篇重要" tabindex="-1">理：为什么这一篇重要 <a class="header-anchor" href="#理-为什么这一篇重要" aria-label="Permalink to &quot;理：为什么这一篇重要&quot;">​</a></h3><p>立命之学之所以重要，不在于它讲了一个逆天改命的励志故事，而在于它把改命这个听起来很玄的事，拆成了可操作的具体行为。</p><p>云谷给的不是鸡汤，而是方法论——</p><p>第一，你必须先看清自己的行为模式。了凡自己说出六条不该中进士的原因时，不是在自我贬低，而是在做一件很少人愿意做的事：诚实面对自己身上的问题。</p><p>第二，改过必须可追踪。功过格就是把变好从一种模糊的感觉，变成可以被数据验证的行为记录。</p><p>第三，心的稳定才是根基。持咒不是求保佑，而是练到念头不动——因为所有的退转，都是从一念滑落开始的。</p><p>这三层合在一起，构成了立命的真正含义：不是求外面的命改变，而是让自己不再做那个能被轻易算定的凡夫。</p><h3 id="用-今天怎么进入这一篇" tabindex="-1">用：今天怎么进入这一篇 <a class="header-anchor" href="#用-今天怎么进入这一篇" aria-label="Permalink to &quot;用：今天怎么进入这一篇&quot;">​</a></h3><p>今天读这篇，不妨做了凡做的第一件事：诚实列出自己身上可能阻碍自己的三条行为模式。不是算命，而是自省——好洁可能是躲避复杂、善怒可能是容不下不同意见、矜惜名节可能是不敢承担犯错的风险。</p><p>有了这三条之后，不必立刻改完。可以先挑一条最简单的，做个微型功过格：每天睡前记一笔——今天有没有因为这个问题产生新的烦恼或错误？坚持一周，看看数据。云谷说三千善行历十馀年，关键不在速度和数量，在不间断。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>人很容易把自己的处境归结为命。关系不顺、事业卡住、性格改不掉——归结为命，就可以不用再努力了。了凡的二十年就是这样过的。</p><p>但他后来发现，命不是被算定的那条线，而是你每天在做的事的总和。如果你好洁、善怒、多言、熬夜、不救人——每个习惯都在一点一点地塑造成你会成为的那个凡人。反过来，如果你从今天开始，哪怕只改一件事——比如不再轻易发怒——你的命就已经开始偏离孔公算的那条线了。</p><p>云谷说的极善之人，数固拘他不定不是一句空话——极善不是指做了什么惊天动地的好事，而是你的行为模式已经超出了那个能被简单预测的范围。改命不是求来的，是活出来的。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p>',20))])}const k=p(u,[["render",g]]);export{P as __pageData,k as default};
